import { NextRequest, NextResponse } from 'next/server';
import { supabase } from '@/lib/supabase';
import { isAdminEmail } from '@/lib/admin-auth';

export const dynamic = 'force-dynamic';

async function getUser(request: NextRequest) {
  // Check if we have a mock user cookie in offline/mock mode
  if (!process.env.NEXT_PUBLIC_SUPABASE_URL || process.env.NEXT_PUBLIC_SUPABASE_URL.includes('your-supabase-url')) {
    const mockUserCookie = request.cookies.get('sp_mock_user');
    if (mockUserCookie) {
      try {
        const email = decodeURIComponent(mockUserCookie.value);
        return {
          id: 'mock-user-id',
          email: email,
        };
      } catch (e) {
        console.error('Failed to parse mock user cookie:', e);
      }
    }
  }

  const authHeader = request.headers.get('Authorization');
  const token = authHeader?.replace('Bearer ', '');
  if (!token) return null;

  try {
    const { data: { user }, error } = await supabase.auth.getUser(token);
    if (error || !user) return null;
    return user;
  } catch (err) {
    console.error('Check route auth error:', err);
    return null;
  }
}

export async function GET(request: NextRequest) {
  const user = await getUser(request);

  // 1. Authenticated User Flow
  if (user) {
    // Check if user is an admin
    if (isAdminEmail(user.email)) {
      return NextResponse.json({
        allowed: true,
        plan: 'Admin',
        reason: 'admin_unlimited_access',
      });
    }

    if (!process.env.NEXT_PUBLIC_SUPABASE_URL) {
      // Offline/Mock mode for registered users (using cookies for state simulation)
      const mockSubCookie = request.cookies.get('sp_mock_subscription');
      let mockSub: any = null;
      if (mockSubCookie) {
        try {
          mockSub = JSON.parse(decodeURIComponent(mockSubCookie.value));
        } catch (e) {
          console.error('Failed to parse mock subscription cookie:', e);
        }
      }

      if (!mockSub) {
        // Automatically initialize default trial if none exists
        const expiryDate = new Date();
        expiryDate.setDate(expiryDate.getDate() + 7);
        mockSub = {
          plan_name: 'Pro',
          billing_cycle: 'Trial',
          status: 'Active',
          start_date: new Date().toISOString(),
          end_date: expiryDate.toISOString(),
          trial_used: true,
          search_count: 0,
          amount: 0,
          payment_id: 'mock_trial_init'
        };
      }

      const isProActive = mockSub.plan_name === 'Pro' && 
                          mockSub.status === 'Active' && 
                          mockSub.billing_cycle !== 'Trial' && 
                          new Date(mockSub.end_date) > new Date();

      const isTrialActive = mockSub.plan_name === 'Pro' && 
                            mockSub.status === 'Active' && 
                            mockSub.billing_cycle === 'Trial' && 
                            new Date(mockSub.end_date) > new Date();

      // Set cookie back in response if it's new
      const responseJson: any = {
        trialUsed: mockSub.trial_used || false,
      };

      if (isProActive) {
        responseJson.allowed = true;
        responseJson.plan = 'Pro';
        responseJson.billingCycle = mockSub.billing_cycle;
        responseJson.reason = 'active_subscription';
      } else if (isTrialActive) {
        const diffMs = new Date(mockSub.end_date).getTime() - Date.now();
        const daysLeft = Math.max(0, Math.ceil(diffMs / (1000 * 60 * 60 * 24)));
        responseJson.allowed = true;
        responseJson.plan = 'Pro';
        responseJson.billingCycle = 'Trial';
        responseJson.trialDaysLeft = daysLeft;
        responseJson.reason = 'active_trial';
      } else {
        // Free user search count check
        const searchesLeft = 2 - (mockSub.search_count || 0);
        if (searchesLeft > 0) {
          responseJson.allowed = true;
          responseJson.plan = 'Free';
          responseJson.searchCount = mockSub.search_count || 0;
          responseJson.reason = 'free_searches_remaining';
        } else {
          responseJson.allowed = false;
          responseJson.plan = 'Free';
          responseJson.searchCount = mockSub.search_count || 0;
          responseJson.reason = mockSub.billing_cycle === 'Trial' ? 'trial_expired' : 'limit_reached';
        }
      }

      const res = NextResponse.json(responseJson);
      if (!mockSubCookie) {
        res.cookies.set('sp_mock_subscription', JSON.stringify(mockSub), {
          path: '/',
          maxAge: 60 * 60 * 24 * 365,
          sameSite: 'lax',
        });
      }
      return res;
    }

    try {
      // Fetch subscription from Supabase
      const { data: subscription, error } = await supabase
        .from('subscriptions')
        .select('*')
        .eq('user_id', user.id)
        .single();

      if (error && error.code !== 'PGRST116') {
        throw error;
      }

      if (!subscription) {
        // Fallback: Create a default trial subscription if it doesn't exist
        const expiryDate = new Date();
        expiryDate.setDate(expiryDate.getDate() + 7);

        const { data: newSub, error: createError } = await supabase
          .from('subscriptions')
          .insert({
            user_id: user.id,
            plan_name: 'Pro',
            billing_cycle: 'Trial',
            status: 'Active',
            start_date: new Date().toISOString(),
            end_date: expiryDate.toISOString(),
            trial_used: true,
            amount: 0,
            payment_id: 'trial_setup'
          })
          .select()
          .single();

        if (createError) throw createError;

        return NextResponse.json({
          allowed: true,
          plan: 'Pro',
          billingCycle: 'Trial',
          trialDaysLeft: 7,
          trialUsed: true,
          reason: 'new_trial_created',
        });
      }

      const isProActive = subscription.plan_name === 'Pro' && 
                          subscription.status === 'Active' && 
                          subscription.billing_cycle !== 'Trial' && 
                          new Date(subscription.end_date) > new Date();

      const isTrialActive = subscription.plan_name === 'Pro' && 
                            subscription.status === 'Active' && 
                            subscription.billing_cycle === 'Trial' && 
                            new Date(subscription.end_date) > new Date();

      const trialUsed = subscription.trial_used || false;

      if (isProActive) {
        return NextResponse.json({
          allowed: true,
          plan: 'Pro',
          billingCycle: subscription.billing_cycle,
          trialUsed,
          reason: 'active_subscription',
        });
      }

      if (isTrialActive) {
        const diffMs = new Date(subscription.end_date).getTime() - Date.now();
        const daysLeft = Math.max(0, Math.ceil(diffMs / (1000 * 60 * 60 * 24)));
        return NextResponse.json({
          allowed: true,
          plan: 'Pro',
          billingCycle: 'Trial',
          trialDaysLeft: daysLeft,
          trialUsed,
          reason: 'active_trial',
        });
      }

      // Free user: count queries in stock_searches
      const { count: searchCount, error: countError } = await supabase
        .from('stock_searches')
        .select('*', { count: 'exact', head: true })
        .eq('user_id', user.id);

      if (countError) throw countError;

      const currentCount = searchCount || 0;
      if (currentCount < 2) {
        return NextResponse.json({
          allowed: true,
          plan: 'Free',
          trialUsed,
          searchCount: currentCount,
          reason: 'free_searches_remaining',
        });
      }

      // Expired trial or inactive subscriptions are blocked
      return NextResponse.json({
        allowed: false,
        plan: 'Free',
        trialUsed,
        searchCount: currentCount,
        reason: subscription.billing_cycle === 'Trial' ? 'trial_expired' : 'limit_reached',
      });

    } catch (err: any) {
      console.error('Supabase subscription check error:', err);
      return NextResponse.json({
        allowed: true,
        plan: 'Free',
        trialUsed: true,
        searchCount: 0,
        reason: 'db_fallback_allowed',
      });
    }
  }

  // 2. Guest User Flow (Unauthenticated)
  const guestSearchesCookie = request.cookies.get('sp_guest_searches');
  const searchCount = guestSearchesCookie ? parseInt(guestSearchesCookie.value, 10) : 0;

  if (searchCount >= 2) {
    return NextResponse.json({
      allowed: false,
      plan: 'Guest',
      reason: 'guest_limit',
      searchCount,
    });
  }

  return NextResponse.json({
    allowed: true,
    plan: 'Guest',
    reason: 'guest_below_limit',
    searchCount,
  });
}

import { NextRequest, NextResponse } from 'next/server';
import { supabase } from '@/lib/supabase';
import { isAdminEmail } from '@/lib/admin-auth';

export const dynamic = 'force-dynamic';

async function getUser(request: NextRequest) {
  // Check if we have a mock user cookie in offline/mock mode
  if (!process.env.NEXT_PUBLIC_SUPABASE_URL || process.env.NEXT_PUBLIC_SUPABASE_URL.includes('your-supabase-url')) {
    const mockUserCookie = request.cookies.get('sp_mock_user');
    if (mockUserCookie) {
      try {
        const email = decodeURIComponent(mockUserCookie.value);
        return {
          id: 'mock-user-id',
          email: email,
        };
      } catch (e) {
        console.error('Failed to parse mock user cookie:', e);
      }
    }
  }

  const authHeader = request.headers.get('Authorization');
  const token = authHeader?.replace('Bearer ', '');
  if (!token) return null;

  try {
    const { data: { user }, error } = await supabase.auth.getUser(token);
    if (error || !user) return null;
    return user;
  } catch (err) {
    console.error('Log route auth error:', err);
    return null;
  }
}

export async function POST(request: NextRequest) {
  const user = await getUser(request);
  let ticker = '';

  try {
    const body = await request.json();
    ticker = (body.ticker || '').toUpperCase();
  } catch (err) {
    // Ticker is optional but recommended
  }

  // 1. Authenticated User flow
  if (user) {
    // Check if user is an admin - skip tracking logs
    if (isAdminEmail(user.email)) {
      return NextResponse.json({ success: true, logged: false, mode: 'admin', reason: 'admin_bypass' });
    }

    if (process.env.NEXT_PUBLIC_SUPABASE_URL) {
      try {
        const { error } = await supabase
          .from('stock_searches')
          .insert({
            user_id: user.id,
            stock_symbol: ticker || 'UNKNOWN',
          });

        if (error) throw error;
      } catch (err) {
        console.error('Failed to log stock search in database:', err);
      }
      return NextResponse.json({ success: true, logged: true, mode: 'user' });
    } else {
      // Mock mode: update search count in cookie
      const mockSubCookie = request.cookies.get('sp_mock_subscription');
      let mockSub: any = null;
      if (mockSubCookie) {
        try {
          mockSub = JSON.parse(decodeURIComponent(mockSubCookie.value));
        } catch (e) {
          console.error('Failed to parse mock subscription cookie:', e);
        }
      }

      if (!mockSub) {
        const expiryDate = new Date();
        expiryDate.setDate(expiryDate.getDate() + 7);
        mockSub = {
          plan_name: 'Pro',
          billing_cycle: 'Trial',
          status: 'Active',
          start_date: new Date().toISOString(),
          end_date: expiryDate.toISOString(),
          trial_used: true,
          search_count: 0,
          amount: 0,
          payment_id: 'mock_trial_init'
        };
      }

      mockSub.search_count = (mockSub.search_count || 0) + 1;

      const response = NextResponse.json({ success: true, logged: true, mode: 'user_mock', count: mockSub.search_count });
      response.cookies.set('sp_mock_subscription', JSON.stringify(mockSub), {
        path: '/',
        maxAge: 60 * 60 * 24 * 365,
        sameSite: 'lax',
      });
      return response;
    }
  }

  // 2. Guest User flow (Unauthenticated)
  const guestSearchesCookie = request.cookies.get('sp_guest_searches');
  const currentCount = guestSearchesCookie ? parseInt(guestSearchesCookie.value, 10) : 0;
  const newCount = currentCount + 1;

  const response = NextResponse.json({
    success: true,
    logged: true,
    mode: 'guest',
    count: newCount,
  });

  // Set the guest count cookie for 1 year
  response.cookies.set('sp_guest_searches', String(newCount), {
    path: '/',
    maxAge: 60 * 60 * 24 * 365,
    httpOnly: true,
    sameSite: 'lax',
  });

  return response;
}

import { NextRequest, NextResponse } from 'next/server';
import { PredictionsDbService } from '@/lib/predictions-db';

export const dynamic = 'force-dynamic';

export async function GET(request: NextRequest) {
  try {
    const origin = request.nextUrl.origin;
    const stats = await PredictionsDbService.getVerificationStats('ALL', origin);

    // Fetch recently verified predictions for public auditing
    const allPredictions = await PredictionsDbService.getAllPredictions();
    const verifiedPredictions = allPredictions
      .filter(r => r.status === 'VERIFIED')
      .sort((a, b) => new Date(b.verification_date || '').getTime() - new Date(a.verification_date || '').getTime())
      .slice(0, 10)
      .map(r => ({
        id: r.id,
        ticker: r.ticker,
        prediction_date: r.prediction_date,
        timeframe: r.timeframe,
        current_price: r.current_price,
        predicted_price: r.predicted_price,
        predicted_direction: r.predicted_direction,
        confidence_score: r.confidence_score,
        actual_price: r.actual_price,
        actual_direction: r.actual_direction,
        prediction_result: r.prediction_result,
        error_percentage: r.error_percentage,
        verification_date: r.verification_date,
      }));

    // Calculate average confidence score
    const allVerified = allPredictions.filter(r => r.status === 'VERIFIED');
    const avgConfidence = allVerified.length > 0
      ? allVerified.reduce((s, r) => s + r.confidence_score, 0) / allVerified.length
      : 0;

    return NextResponse.json({
      accuracy: stats.tradeableAccuracy ?? stats.accuracy,
      overallAccuracy: stats.overallModelAccuracy ?? stats.accuracy,
      tradeableAccuracy: stats.tradeableAccuracy ?? stats.accuracy,
      totalCount: stats.totalCount,
      totalVerified: stats.totalCount,
      filteredPredictionsCount: stats.filteredPredictionsCount,
      noSignalCount: stats.noSignalCount,
      avgConfidence: Number(avgConfidence.toFixed(1)),
      confidenceCalibration: stats.confidenceCalibration,
      accuracyTrend: stats.accuracyTrend,
      recentVerified: verifiedPredictions,
      accuracyByModel: stats.accuracyByModel,
      avgError: stats.avgError,
      medianError: stats.medianError,
      winLossRatioAfterFiltering: stats.winLossRatioAfterFiltering,
      brierScore: stats.brierScore,
      overallWinLossRatio: stats.overallWinLossRatio ?? stats.winLossRatio,
      accuracyBeforeFiltering: stats.accuracyBeforeFiltering ?? stats.accuracy,
      accuracyAfterFiltering: stats.accuracyAfterFiltering ?? stats.tradeableAccuracy ?? stats.accuracy,
      failureAnalysis: stats.failureAnalysis,
      stockReliability: stats.stockReliability ?? stats.accuracyByStock,
      timeframeReliability: stats.timeframeReliability,
      confidenceBucketPerformance: stats.confidenceBucketPerformance,
      targetAchieved: stats.targetAchieved,
    });
  } catch (err: any) {
    console.error('Failed to fetch public trust stats:', err);
    return NextResponse.json({ error: err.message || 'Failed to retrieve trust statistics.' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { supabase } from '@/lib/supabase';
import { StockData } from '@/types/stock';

export const dynamic = 'force-dynamic';

// Helper to authenticate user via JWT token
async function getUser(request: NextRequest) {
  const authHeader = request.headers.get('Authorization');
  const token = authHeader?.replace('Bearer ', '');

  if (!token) return null;

  try {
    const { data: { user }, error } = await supabase.auth.getUser(token);
    if (error || !user) return null;
    return user;
  } catch (err) {
    console.error('Auth check error:', err);
    return null;
  }
}

// In-memory mock watchlist for local fallback
let mockWatchlist = ['AAPL', 'MSFT', 'TSLA'];

export async function GET(request: NextRequest) {
  const user = await getUser(request);
  const baseUrl = request.nextUrl.origin;

  let tickers: string[] = [];

  // 1. Fetch tickers from Supabase if authenticated
  if (user && process.env.NEXT_PUBLIC_SUPABASE_URL) {
    try {
      const { data, error } = await supabase
        .from('watchlist')
        .select('ticker')
        .eq('user_id', user.id);

      if (error) throw error;
      tickers = data.map((item: { ticker: string }) => item.ticker);
    } catch (err) {
      console.error('Error fetching watchlist from Supabase, using mock:', err);
      tickers = mockWatchlist;
    }
  } else {
    // Guest / Mock mode
    tickers = mockWatchlist;
  }

  // 2. Fetch live quote data for each ticker in the watchlist
  const watchlistItems = await Promise.all(
    tickers.map(async (ticker) => {
      try {
        const res = await fetch(`${baseUrl}/api/stock/${ticker}`, { cache: 'no-store' });
        if (res.ok) {
          const stockData: StockData = await res.json();
          return {
            id: ticker,
            user_id: user?.id || 'guest',
            ticker,
            added_at: new Date().toISOString(),
            price: stockData.quote.price,
            changePercent: stockData.quote.changePercent,
            history: stockData.history.slice(-30), // 30 days history for sparkline
          };
        }
      } catch (err) {
        console.error(`Error fetching live quote for watchlist item ${ticker}:`, err);
      }
      return {
        id: ticker,
        user_id: user?.id || 'guest',
        ticker,
        added_at: new Date().toISOString(),
        price: 150,
        changePercent: 0,
        history: [],
      };
    })
  );

  return NextResponse.json(watchlistItems);
}

export async function POST(request: NextRequest) {
  const user = await getUser(request);

  try {
    const { ticker, action } = await request.json();
    if (!ticker) {
      return NextResponse.json({ error: 'Ticker is required' }, { status: 400 });
    }

    const cleanTicker = ticker.toUpperCase();

    // 1. Handle authenticated Supabase request
    if (user && process.env.NEXT_PUBLIC_SUPABASE_URL) {
      if (action === 'add') {
        const { error } = await supabase
          .from('watchlist')
          .upsert({ user_id: user.id, ticker: cleanTicker }, { onConflict: 'user_id,ticker' });

        if (error) throw error;
        return NextResponse.json({ success: true, action: 'add', ticker: cleanTicker });
      } else if (action === 'remove') {
        const { error } = await supabase
          .from('watchlist')
          .delete()
          .eq('user_id', user.id)
          .eq('ticker', cleanTicker);

        if (error) throw error;
        return NextResponse.json({ success: true, action: 'remove', ticker: cleanTicker });
      }
    }

    // 2. Handle guest/mock mode fallback
    if (action === 'add') {
      if (!mockWatchlist.includes(cleanTicker)) {
        mockWatchlist.push(cleanTicker);
      }
      return NextResponse.json({ success: true, action: 'add', ticker: cleanTicker });
    } else if (action === 'remove') {
      mockWatchlist = mockWatchlist.filter((t) => t !== cleanTicker);
      return NextResponse.json({ success: true, action: 'remove', ticker: cleanTicker });
    }

    return NextResponse.json({ error: 'Invalid action' }, { status: 400 });
  } catch (err: any) {
    console.error('Watchlist mutation error:', err);
    return NextResponse.json({ error: err.message || 'Operation failed' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { supabase } from '@/lib/supabase';

export const dynamic = 'force-dynamic';

export async function POST(request: NextRequest) {
  try {
    const bodyText = await request.text();
    const headers = request.headers;

    let eventType = '';
    let userId = '';
    let amount = 0;
    let currency = 'INR';
    let planId = 'monthly';
    let transactionId = '';
    let provider = 'Unknown';
    let isSuccess = false;

    // Check header signature type to differentiate Stripe vs Razorpay
    const stripeSignature = headers.get('stripe-signature');
    const razorpaySignature = headers.get('x-razorpay-signature');

    if (stripeSignature) {
      provider = 'Stripe';
      const event = JSON.parse(bodyText);
      eventType = event.type;

      if (eventType === 'checkout.session.completed' || eventType === 'invoice.payment_succeeded') {
        const session = event.data?.object;
        userId = session?.client_reference_id || session?.metadata?.userId;
        amount = (session?.amount_total || 0) / 100; // Stripe uses cents
        currency = (session?.currency || 'inr').toUpperCase();
        planId = session?.metadata?.planId || 'monthly';
        transactionId = session?.id || session?.payment_intent;
        isSuccess = session?.payment_status === 'paid' || eventType === 'invoice.payment_succeeded';
      }
    } else if (razorpaySignature) {
      provider = 'Razorpay';
      const event = JSON.parse(bodyText);
      eventType = event.event;

      if (eventType === 'payment.captured' || eventType === 'subscription.charged') {
        const payload = event.payload?.payment?.entity;
        userId = payload?.notes?.userId || event.payload?.subscription?.entity?.notes?.userId;
        amount = (payload?.amount || 0) / 100; // Razorpay uses paise
        currency = (payload?.currency || 'INR').toUpperCase();
        planId = payload?.notes?.planId || 'monthly';
        transactionId = payload?.id;
        isSuccess = payload?.status === 'captured';
      }
    } else {
      // Mock / direct webhook endpoint simulation for developer testing
      const mockEvent = JSON.parse(bodyText);
      provider = mockEvent.provider || 'Mock';
      userId = mockEvent.userId;
      amount = mockEvent.amount || 999;
      currency = mockEvent.currency || 'INR';
      planId = mockEvent.planId || 'monthly';
      transactionId = mockEvent.transactionId || `mock_webhook_${Date.now()}`;
      isSuccess = mockEvent.status === 'Success';
    }

    if (isSuccess && userId && process.env.NEXT_PUBLIC_SUPABASE_URL) {
      // Calculate expiry date based on plan
      const expiryDate = new Date();
      if (planId === 'weekly') expiryDate.setDate(expiryDate.getDate() + 7);
      else if (planId === 'monthly') expiryDate.setDate(expiryDate.getDate() + 30);
      else if (planId === 'yearly') expiryDate.setDate(expiryDate.getDate() + 365);

      console.log(`[Webhook] Success checkout for user ${userId}. Plan: ${planId}. Provider: ${provider}`);

      // 1. Upsert subscription record
      const { error: subError } = await supabase
        .from('subscriptions')
        .upsert({
          user_id: userId,
          plan_name: 'Pro',
          billing_cycle: planId.charAt(0).toUpperCase() + planId.slice(1),
          status: 'Active',
          start_date: new Date().toISOString(),
          end_date: expiryDate.toISOString(),
          trial_used: true,
        }, { onConflict: 'user_id' });

      if (subError) {
        console.error('[Webhook] Failed to update subscription:', subError);
        throw subError;
      }

      // 2. Insert payment record
      const { error: payError } = await supabase
        .from('payments')
        .insert({
          user_id: userId,
          amount: amount,
          currency: currency,
          payment_provider: provider,
          status: 'Success',
          transaction_id: transactionId,
        });

      if (payError) {
        console.error('[Webhook] Failed to log payment:', payError);
        throw payError;
      }
    }

    return NextResponse.json({ received: true, processed: isSuccess });

  } catch (err: any) {
    console.error('[Webhook API] Processing Error:', err);
    return NextResponse.json({ error: err.message || 'Webhook processing failed.' }, { status: 500 });
  }
}

