// Helpers
function calculateWLRatio(predictions: PredictionRecord[]): number {
  let winSum = 0;
  let winCount = 0;
  let lossSum = 0;
  let lossCount = 0;

  predictions.forEach(p => {
    if (p.prediction_result === 'CORRECT') {
      winSum += (p.error_percentage || 0);
      winCount++;
    } else {
      lossSum += (p.error_percentage || 0);
      lossCount++;
    }
  });

  if (lossCount === 0 || lossSum === 0) return winCount > 0 ? 999 : 0;
  if (winCount === 0 || winSum === 0) return 0;

  const avgWin = winSum / winCount;
  const avgLoss = lossSum / lossCount;
  return avgWin / avgLoss;
}

function calculateMedianError(predictions: PredictionRecord[]): number {
  const errors = predictions.map(r => r.error_percentage || 0).sort((a, b) => a - b);
  return errors.length > 0 ? errors[Math.floor(errors.length / 2)] * 100 : 0;
}

function calculateBrierScore(predictions: PredictionRecord[]): number {
  if (predictions.length === 0) return 0;
  let brierSum = 0;
  predictions.forEach(p => {
    const conf = (p.confidence_score ?? 50) / 100;
    const outcome = p.prediction_result === 'CORRECT' ? 1 : 0;
    brierSum += Math.pow(conf - outcome, 2);
  });
  return brierSum / predictions.length;
}

function computeMetricsForGroup(key: string, predictions: PredictionRecord[], minSampleSize: number): AggregateMetrics {
  const total = predictions.length;
  const correct = predictions.filter(p => p.prediction_result === 'CORRECT').length;
  const wrong = total - correct;
  const accuracy = total > 0 ? (correct / total) * 100 : 0;

  const tradeable = predictions.filter(p => p.is_tradeable_signal === true);
  const tradeableCount = tradeable.length;
  const tradeableCorrect = tradeable.filter(p => p.prediction_result === 'CORRECT').length;
  const tradeableAccuracy = tradeableCount > 0 ? (tradeableCorrect / tradeableCount) * 100 : 0;

  const avgConf = total > 0 ? predictions.reduce((sum, p) => sum + (p.confidence_score ?? 50), 0) / total : 0;
  const calibrationGap = avgConf - accuracy;

  const winLossRatio = calculateWLRatio(predictions);
  const medianError = calculateMedianError(predictions);
  const brierScore = calculateBrierScore(predictions);

  const eceData = predictions.map(p => ({
    prob: (p.confidence_score ?? 50) / 100,
    actual: p.prediction_result === 'CORRECT' ? 1 : 0
  }));
  const ece = eceData.length > 0 ? calculateECE(eceData) * 100 : 0;

  return {
    key,
    totalPredictions: total,
    correctPredictions: correct,
    wrongPredictions: wrong,
    accuracy,
    tradeableCount,
    tradeableAccuracy,
    averageConfidence: avgConf,
    calibrationGap,
    medianError,
    winLossRatio,
    brierScore,
    ece,
    sampleSizeWarning: total < minSampleSize
  };
}

export function tagFailureReasons(record: PredictionRecord): FailureReason[] {
  const reasons: FailureReason[] = [];
  if (record.prediction_result !== 'INCORRECT') return reasons;

  // Evaluate tags
  const conf = record.confidence_score ?? 50;
  if (conf > 80) reasons.push('OVERCONFIDENT_SIGNAL');

  if (record.volatility_regime === 'HIGH_VOLATILITY') reasons.push('HIGH_VOLATILITY_FAILURE');

  // A crude timeframe conflict check based on signal strength vs confidence, 
  // or if we had smart features available we could read `timeframeConflict`.
  if (record.smart_features && (record.smart_features as any).timeframeConflict) {
    reasons.push('TIMEFRAME_CONFLICT');
  }

  // Price gap event if error percentage is huge (e.g. > 10% on a short timeframe)
  if ((record.error_percentage || 0) > 0.10 && record.timeframe !== '1Y') {
    reasons.push('PRICE_GAP_EVENT');
  }

  // Add more specific logic based on market regime vs predicted direction
  if (record.trend_regime === 'BEAR_MARKET' && record.predicted_direction === 'UP') {
    reasons.push('AGAINST_MARKET_TREND');
  } else if (record.trend_regime === 'BULL_MARKET' && record.predicted_direction === 'DOWN') {
    reasons.push('AGAINST_MARKET_TREND');
  } else if (record.trend_regime === 'SIDEWAYS_MARKET') {
    reasons.push('WRONG_REGIME');
  }

  if (reasons.length === 0) {
    reasons.push('UNKNOWN_REASON');
  }

  return reasons;
}

function getConfidenceBucket(conf: number): string {
  if (conf < 55) return 'Below 55%';
  if (conf < 65) return '55–65%';
  if (conf < 75) return '65–75%';
  if (conf < 85) return '75–85%';
  return 'Above 85%';
}

export function buildFailureAnalysisReport(verifiedPredictions: PredictionRecord[]): FailureAnalysisReport {
  const groups: Record<string, Record<string, PredictionRecord[]>> = {
    stocks: {},
    sectors: {},
    trendRegimes: {},
    volatilityRegimes: {},
    combinedRegimes: {},
    timeframes: {},
    confidenceBuckets: {},
    signalTypes: {}
  };

  const topFailureReasons: Record<string, number> = {};

  for (const pred of verifiedPredictions) {
    const stock = pred.ticker;
    const sector = getSector(stock);
    const trend = pred.trend_regime || 'UNKNOWN';
    const vol = pred.volatility_regime || 'UNKNOWN';
    const combinedRegime = `${trend} + ${vol}`;
    const tf = pred.timeframe;
    const confBucket = getConfidenceBucket(pred.confidence_score ?? 50);
    const signal = pred.signal_strength || 'UNKNOWN';

    groups.stocks[stock] = groups.stocks[stock] || []; groups.stocks[stock].push(pred);
    groups.sectors[sector] = groups.sectors[sector] || []; groups.sectors[sector].push(pred);
    groups.trendRegimes[trend] = groups.trendRegimes[trend] || []; groups.trendRegimes[trend].push(pred);
    groups.volatilityRegimes[vol] = groups.volatilityRegimes[vol] || []; groups.volatilityRegimes[vol].push(pred);
    groups.combinedRegimes[combinedRegime] = groups.combinedRegimes[combinedRegime] || []; groups.combinedRegimes[combinedRegime].push(pred);
    groups.timeframes[tf] = groups.timeframes[tf] || []; groups.timeframes[tf].push(pred);
    groups.confidenceBuckets[confBucket] = groups.confidenceBuckets[confBucket] || []; groups.confidenceBuckets[confBucket].push(pred);
    groups.signalTypes[signal] = groups.signalTypes[signal] || []; groups.signalTypes[signal].push(pred);

    if (pred.prediction_result === 'INCORRECT') {
      const reasons = tagFailureReasons(pred);
      for (const r of reasons) {
        topFailureReasons[r] = (topFailureReasons[r] || 0) + 1;
      }
    }
  }

  // Convert groups to AggregateMetrics
  const mapGroup = (groupMap: Record<string, PredictionRecord[]>, minSize: number) => {
    return Object.entries(groupMap).map(([key, preds]) => computeMetricsForGroup(key, preds, minSize));
  };

  const stocks = mapGroup(groups.stocks, 50);
  const sectors = mapGroup(groups.sectors, 100);
  const trendRegimes = mapGroup(groups.trendRegimes, 100);
  const volatilityRegimes = mapGroup(groups.volatilityRegimes, 100);
  const combinedRegimes = mapGroup(groups.combinedRegimes, 100);
  const timeframes = mapGroup(groups.timeframes, 100);
  const confidenceBuckets = mapGroup(groups.confidenceBuckets, 100);
  const signalTypes = mapGroup(groups.signalTypes, 100);

  // Generate Recommendations
  sectors.forEach(s => {
    if (!s.sampleSizeWarning && s.accuracy < 50) {
      s.recommendation = `Reduce confidence or avoid strong signals in ${s.key} sector until performance improves.`;
    }
  });

  trendRegimes.forEach(r => {
    if (!r.sampleSizeWarning && r.accuracy < 50) {
      r.recommendation = `Downgrade signals during ${r.key} markets. Accuracy is critically low.`;
    }
  });

  confidenceBuckets.forEach(b => {
    if (!b.sampleSizeWarning && b.key === 'Above 85%' && b.accuracy < 75) {
      b.recommendation = `Model is overconfident in high-confidence predictions (Gap: ${b.calibrationGap.toFixed(1)}%). Calibration needs adjustment.`;
    }
  });

  return {
    stocks,
    sectors,
    trendRegimes,
    volatilityRegimes,
    combinedRegimes,
    timeframes,
    confidenceBuckets,
    signalTypes,
    topFailureReasons: topFailureReasons as Record<FailureReason, number>
  };
}

import { HistoricalQuote, TechnicalIndicators } from '../types/stock';
import { SMA, EMA, ATR } from 'technicalindicators';

export interface SmartFeatures {
  // Trend Features
  trendStrength: number;
  trendDuration: number;
  emaDistance20: number;
  emaDistance50: number;
  emaDistance200: number;
  emaSlope20: number;
  emaSlope50: number;
  emaSlope200: number;

  // Volatility Features
  atrExpansion: number;
  atrCompressionPercentile: number;
  rollingVolatility20: number;
  rollingVolatility50: number;
  volatilityPercentile100: number;

  // Volume Features
  relativeVolume: number;
  volumeAcceleration: number;
  volumeConfirmationScore: number;

  // Market Features
  indexStrength: number;
  sectorStrength: number;
  relativePerformance5: number;
  relativePerformance20: number;
  relativePerformance60: number;

  // Multi-Timeframe Features
  higherTimeframeTrend: number; // 1 (Bull), -1 (Bear), 0 (Neutral)
  higherTimeframeStrength: number;
  alignmentScore: number;
  timeframeConflict: number; // 1 (Conflict), 0 (No Conflict)

  // Macro Features (Priority 10)
  macroNiftyStrength: number;
  macroBankNiftyStrength: number;
  macroVixLevel: number;
  macroVixPercentile: number;
  macroInterestRateTrend: number; // 1 (Rising), -1 (Falling), 0 (Flat)
  macroUsdInrTrend: number;       // 1 (Rising), -1 (Falling), 0 (Flat)
  macroRiskScore: number;
}

export interface ScalerMetadata {
  means: Record<string, number>;
  stds: Record<string, number>;
}

import { resampleBars, analyzeTimeframe, calculateAlignment } from './multiTimeframeAnalysis';
import { MacroContext } from './macroContext';

export function extractFeatures(
  bars: HistoricalQuote[],
  currentIndex: number,
  indexBars?: HistoricalQuote[],
  sectorBars?: HistoricalQuote[],
  macroContext?: MacroContext
): SmartFeatures {
  const slice = bars.slice(0, currentIndex + 1);
  if (slice.length < 200) {
    throw new Error('Not enough historical bars to extract features (requires at least 200)');
  }

  const closes = slice.map(b => b.close);
  const highs = slice.map(b => b.high);
  const lows = slice.map(b => b.low);
  const volumes = slice.map(b => b.volume);
  const currentPrice = closes[closes.length - 1];

  // Moving Averages
  const ema20Arr = EMA.calculate({ values: closes, period: 20 });
  const ema50Arr = EMA.calculate({ values: closes, period: 50 });
  const ema200Arr = EMA.calculate({ values: closes, period: 200 });

  const ema20 = ema20Arr.length > 0 ? ema20Arr[ema20Arr.length - 1] : currentPrice;
  const ema50 = ema50Arr.length > 0 ? ema50Arr[ema50Arr.length - 1] : currentPrice;
  const ema200 = ema200Arr.length > 0 ? ema200Arr[ema200Arr.length - 1] : currentPrice;

  // EMA Distances
  const emaDistance20 = (currentPrice - ema20) / ema20;
  const emaDistance50 = (currentPrice - ema50) / ema50;
  const emaDistance200 = (currentPrice - ema200) / ema200;

  // EMA Slopes (Normalized by EMA)
  const safeGet = (arr: number[], offset: number, fallback: number) => 
    arr.length > offset ? arr[arr.length - 1 - offset] : fallback;

  const emaSlope20 = (ema20 - safeGet(ema20Arr, 5, ema20)) / safeGet(ema20Arr, 5, ema20);
  const emaSlope50 = (ema50 - safeGet(ema50Arr, 10, ema50)) / safeGet(ema50Arr, 10, ema50);
  const emaSlope200 = (ema200 - safeGet(ema200Arr, 20, ema200)) / safeGet(ema200Arr, 20, ema200);

  // Trend Strength (0 to 1) based on EMA alignment and slopes
  let trendStrength = 0;
  if (ema20 > ema50 && ema50 > ema200) trendStrength += 0.4;
  else if (ema20 < ema50 && ema50 < ema200) trendStrength += 0.4; // Strong bearish is still a strong trend
  if (Math.abs(emaSlope20) > 0.01) trendStrength += 0.2;
  if (Math.abs(emaDistance200) > 0.1) trendStrength += 0.2;

  // Highs and Lows analysis for trend strength
  const last10Closes = closes.slice(-10);
  let higherHighs = 0, lowerLows = 0;
  for (let i = 1; i < last10Closes.length; i++) {
    if (last10Closes[i] > last10Closes[i-1]) higherHighs++;
    if (last10Closes[i] < last10Closes[i-1]) lowerLows++;
  }
  if (higherHighs >= 7 || lowerLows >= 7) trendStrength += 0.2;
  trendStrength = Math.min(1, Math.max(0, trendStrength));

  // Trend Duration
  let trendDuration = 0;
  const isBullish = ema20 > ema50;
  for (let i = 0; i < Math.min(ema20Arr.length, ema50Arr.length); i++) {
    const e20 = ema20Arr[ema20Arr.length - 1 - i];
    const e50 = ema50Arr[ema50Arr.length - 1 - i];
    if ((e20 > e50) === isBullish) {
      trendDuration++;
    } else {
      break;
    }
  }

  // ATR & Volatility
  const atrArr = ATR.calculate({ high: highs, low: lows, close: closes, period: 14 });
  const currentATR = atrArr.length > 0 ? atrArr[atrArr.length - 1] : (currentPrice * 0.02);
  const atrSma50Arr = SMA.calculate({ values: atrArr, period: 50 });
  const avgATR50 = atrSma50Arr.length > 0 ? atrSma50Arr[atrSma50Arr.length - 1] : currentATR;

  const atrExpansion = avgATR50 > 0 ? currentATR / avgATR50 : 1;

  // ATR Compression Percentile
  const last100ATRs = atrArr.slice(-100);
  const atrCompressionPercentile = last100ATRs.length > 0 
    ? last100ATRs.filter(v => v < currentATR).length / last100ATRs.length 
    : 0.5;

  // Rolling Volatility (using log returns)
  const logReturns: number[] = [];
  for (let i = 1; i < closes.length; i++) {
    logReturns.push(Math.log(closes[i] / closes[i - 1]));
  }

  const calcVol = (period: number) => {
    if (logReturns.length < period) return 0;
    const slice = logReturns.slice(-period);
    const mean = slice.reduce((a, b) => a + b, 0) / period;
    const variance = slice.reduce((a, b) => a + Math.pow(b - mean, 2), 0) / period;
    return Math.sqrt(variance);
  };

  const rollingVolatility20 = calcVol(20);
  const rollingVolatility50 = calcVol(50);

  const last100Vols = [];
  for (let i = 0; i < 100; i++) {
    if (logReturns.length - i >= 20) {
      const slice = logReturns.slice(logReturns.length - 20 - i, logReturns.length - i);
      const mean = slice.reduce((a, b) => a + b, 0) / 20;
      const variance = slice.reduce((a, b) => a + Math.pow(b - mean, 2), 0) / 20;
      last100Vols.push(Math.sqrt(variance));
    }
  }
  const volatilityPercentile100 = last100Vols.length > 0
    ? last100Vols.filter(v => v < rollingVolatility20).length / last100Vols.length
    : 0.5;

  // Volume Features
  const last20Vols = volumes.slice(-20);
  const avgVol20 = last20Vols.reduce((a, b) => a + b, 0) / last20Vols.length;
  const relativeVolume = avgVol20 > 0 ? volumes[volumes.length - 1] / avgVol20 : 1;

  const last5Vols = volumes.slice(-5);
  const avgVol5 = last5Vols.reduce((a, b) => a + b, 0) / last5Vols.length;
  const volumeAcceleration = avgVol20 > 0 ? avgVol5 / avgVol20 : 1;

  let volumeConfirmationScore = 0;
  const priceUp = closes[closes.length - 1] > closes[closes.length - 2];
  if (priceUp && relativeVolume > 1) volumeConfirmationScore = 1; // bullish confirmation
  else if (!priceUp && relativeVolume > 1) volumeConfirmationScore = -1; // bearish confirmation
  else volumeConfirmationScore = 0; // low confidence

  // Market Features (using indexBars if provided, else fallback to 0/neutral)
  let indexStrength = 0;
  let relativePerformance5 = 0;
  let relativePerformance20 = 0;
  let relativePerformance60 = 0;

  if (indexBars && indexBars.length > 0) {
    const idxCloses = indexBars.slice(0, currentIndex + 1).map(b => b.close);
    if (idxCloses.length >= 200) {
      const idxEma50Arr = EMA.calculate({ values: idxCloses, period: 50 });
      const idxEma200Arr = EMA.calculate({ values: idxCloses, period: 200 });
      const idxCurrent = idxCloses[idxCloses.length - 1];
      const idxEma50 = idxEma50Arr[idxEma50Arr.length - 1];
      const idxEma200 = idxEma200Arr[idxEma200Arr.length - 1];

      if (idxCurrent > idxEma50) indexStrength += 0.5;
      if (idxCurrent > idxEma200) indexStrength += 0.5;

      const calcRelPerf = (period: number) => {
        if (closes.length < period || idxCloses.length < period) return 0;
        const stockRet = (closes[closes.length - 1] - closes[closes.length - period]) / closes[closes.length - period];
        const idxRet = (idxCloses[idxCloses.length - 1] - idxCloses[idxCloses.length - period]) / idxCloses[idxCloses.length - period];
        return stockRet - idxRet;
      };

      relativePerformance5 = calcRelPerf(5);
      relativePerformance20 = calcRelPerf(20);
      relativePerformance60 = calcRelPerf(60);
    }
  }

  // Sector Features (fallback to neutral if none)
  const sectorStrength = 0;

  // Multi-Timeframe Analysis
  const primaryAnalysis = analyzeTimeframe(slice, false);
  const lowerAnalysis = analyzeTimeframe(slice, true); // proxy for momentum
  const weeklyBars = resampleBars(slice, 'W');
  const higherAnalysis = analyzeTimeframe(weeklyBars, false);

  const mtfResult = calculateAlignment(higherAnalysis, primaryAnalysis, lowerAnalysis);

  const mapTrend = (t: string) => t === 'BULLISH' ? 1 : t === 'BEARISH' ? -1 : 0;
  const higherTimeframeTrend = mapTrend(mtfResult.higherTimeframeTrend);
  const alignmentScore = mtfResult.alignmentScore;
  const timeframeConflict = mtfResult.alignmentScore < 40 ? 1 : 0;

  // Priority 10: Extract Macro Features
  const macroNiftyStrength = macroContext ? macroContext.niftyStrength : 50;
  const macroBankNiftyStrength = macroContext ? macroContext.bankNiftyStrength : 50;
  const macroVixLevel = macroContext ? macroContext.vixLevel : 15;
  const macroVixPercentile = macroContext ? macroContext.vixPercentile : 50;
  const macroInterestRateTrend = macroContext ? (macroContext.interestRateTrend === 'RISING' ? 1 : macroContext.interestRateTrend === 'FALLING' ? -1 : 0) : 0;
  const macroUsdInrTrend = macroContext ? (macroContext.usdInrTrend === 'RISING' ? 1 : macroContext.usdInrTrend === 'FALLING' ? -1 : 0) : 0;
  const macroRiskScore = macroContext ? macroContext.macroRiskScore : 50;

  return {
    trendStrength,
    trendDuration,
    emaDistance20,
    emaDistance50,
    emaDistance200,
    emaSlope20,
    emaSlope50,
    emaSlope200,
    atrExpansion,
    atrCompressionPercentile,
    rollingVolatility20,
    rollingVolatility50,
    volatilityPercentile100,
    relativeVolume,
    volumeAcceleration,
    volumeConfirmationScore,
    indexStrength,
    sectorStrength,
    relativePerformance5,
    relativePerformance20,
    relativePerformance60,
    higherTimeframeTrend,
    higherTimeframeStrength: higherAnalysis.trendStrength,
    alignmentScore,
    timeframeConflict,
    macroNiftyStrength,
    macroBankNiftyStrength,
    macroVixLevel,
    macroVixPercentile,
    macroInterestRateTrend,
    macroUsdInrTrend,
    macroRiskScore
  };
}

/**
 * Fits a robust scaler using training records to prevent leakage.
 * Uses Z-score standardization (0 mean, 1 std dev).
 */
export function fitScaler(trainFeatures: SmartFeatures[]): ScalerMetadata {
  if (trainFeatures.length === 0) {
    return { means: {}, stds: {} };
  }

  const keys = Object.keys(trainFeatures[0]) as (keyof SmartFeatures)[];
  const means: Record<string, number> = {};
  const stds: Record<string, number> = {};

  for (const key of keys) {
    const values = trainFeatures.map(f => f[key] as number);
    const mean = values.reduce((a, b) => a + b, 0) / values.length;
    const variance = values.reduce((a, b) => a + Math.pow(b - mean, 2), 0) / values.length;
    means[key] = mean;
    stds[key] = Math.sqrt(variance);
  }

  return { means, stds };
}

/**
 * Applies the fitted scaler to raw features safely.
 */
export function transformFeatures(features: SmartFeatures, scaler: ScalerMetadata): SmartFeatures {
  const scaled = { ...features };
  const keys = Object.keys(features) as (keyof SmartFeatures)[];

  for (const key of keys) {
    const mean = scaler.means[key] ?? 0;
    const std = scaler.stds[key] ?? 1;
    const safeStd = std === 0 ? 1 : std; // Prevent div by zero
    (scaled as any)[key] = ((features[key] as number) - mean) / safeStd;
  }

  return scaled;
}

import { isSupabaseConfigured } from './db';

export interface JobStatus {
  id: string;
  status: 'QUEUED' | 'RUNNING' | 'COMPLETED' | 'FAILED' | 'CANCELLED';
  progress: number; // 0 to 100
  recordsProcessed: number;
  totalRecords: number;
  recordsVerified: number;
  databaseWrites: number; // successfulWrites
  failedWrites?: number;
  skippedRows?: number;
  successRate: number;
  executionTime: number; // in ms
  startedAt: string;
  estimatedTimeRemaining: number; // in seconds
  error?: string;
  failures: string[];
}

const getMockJobsPath = () => {
  if (typeof window !== 'undefined') return '';
  const path = require('path');
  return path.join(process.cwd(), 'lib', 'mock-jobs-db.json');
};

const readMockJobs = (): Record<string, JobStatus> => {
  if (typeof window !== 'undefined') return {};
  const fs = require('fs');
  const dbPath = getMockJobsPath();
  try {
    if (fs.existsSync(dbPath)) {
      const data = fs.readFileSync(dbPath, 'utf8');
      return JSON.parse(data) || {};
    }
  } catch (err) {
    console.error('Error reading mock jobs DB:', err);
  }
  return {};
};

const writeMockJobs = (data: Record<string, JobStatus>): boolean => {
  if (typeof window !== 'undefined') return false;
  const fs = require('fs');
  const dbPath = getMockJobsPath();
  try {
    fs.writeFileSync(dbPath, JSON.stringify(data, null, 2), 'utf8');
    return true;
  } catch (err) {
    console.error('Error writing mock jobs DB:', err);
    return false;
  }
};

// Fallback in-memory cache
const inMemoryJobs: Record<string, JobStatus> = {};

export const JobsDbService = {
  async createJob(id: string, totalRecords: number): Promise<JobStatus> {
    const job: JobStatus = {
      id,
      status: 'QUEUED',
      progress: 0,
      recordsProcessed: 0,
      totalRecords,
      recordsVerified: 0,
      databaseWrites: 0,
      successRate: 0,
      executionTime: 0,
      startedAt: new Date().toISOString(),
      estimatedTimeRemaining: 0,
      failures: [],
    };

    inMemoryJobs[id] = job;
    const db = readMockJobs();
    db[id] = job;
    writeMockJobs(db);

    return job;
  },

  async updateJobProgress(id: string, updates: Partial<JobStatus>): Promise<JobStatus> {
    const db = readMockJobs();
    const current = db[id] || inMemoryJobs[id];

    if (!current) {
      throw new Error(`Job with ID ${id} not found.`);
    }

    const updatedJob: JobStatus = {
      ...current,
      ...updates,
      id,
    };

    // Calculate execution time dynamically
    const elapsedMs = Date.now() - new Date(updatedJob.startedAt).getTime();
    updatedJob.executionTime = elapsedMs;

    if (updatedJob.status === 'RUNNING') {
      // Estimate time remaining
      if (updatedJob.progress > 0 && updatedJob.progress < 100) {
        const timePerPercent = elapsedMs / updatedJob.progress;
        const remainingPercent = 100 - updatedJob.progress;
        updatedJob.estimatedTimeRemaining = Math.max(0, Math.round((timePerPercent * remainingPercent) / 1000));
      }
    } else if (updatedJob.status === 'COMPLETED' || updatedJob.status === 'FAILED' || updatedJob.status === 'CANCELLED') {
      updatedJob.estimatedTimeRemaining = 0;
    }

    inMemoryJobs[id] = updatedJob;
    db[id] = updatedJob;
    writeMockJobs(db);

    return updatedJob;
  },

  async getJobStatus(id: string): Promise<JobStatus | null> {
    const db = readMockJobs();
    const job = db[id] || inMemoryJobs[id];
    return job || null;
  },

  async cancelJob(id: string): Promise<JobStatus | null> {
    const db = readMockJobs();
    const current = db[id] || inMemoryJobs[id];

    if (!current) return null;

    const cancelledJob: JobStatus = {
      ...current,
      status: 'CANCELLED',
      estimatedTimeRemaining: 0,
    };

    inMemoryJobs[id] = cancelledJob;
    db[id] = cancelledJob;
    writeMockJobs(db);

    return cancelledJob;
  },
};

import { HistoricalQuote, TechnicalIndicators } from '../types/stock';

export type TrendRegime = 'BULL_MARKET' | 'BEAR_MARKET' | 'SIDEWAYS_MARKET';
export type VolatilityRegime = 'HIGH_VOLATILITY' | 'NORMAL_VOLATILITY' | 'LOW_VOLATILITY';

export interface MarketRegimeClassification {
  trendRegime: TrendRegime;
  volatilityRegime: VolatilityRegime;
  regimeConfidence: number; // 0-1
  regimeReason: string;
}

export function detectMarketRegime(
  indicators: TechnicalIndicators,
  price: number,
  context?: { history?: HistoricalQuote[]; volume?: number }
): MarketRegimeClassification {
  const {
    sma20,
    sma50,
    sma200,
    atr14,
  } = indicators;

  // Trend detection
  const recent = context?.history?.slice(-30) ?? [];
  let ema20Slope = 0;
  let ema50Slope = 0;

  if (recent.length >= 5) {
    const p1 = recent[recent.length - 1].close;
    const p5 = recent[recent.length - 5].close;
    ema20Slope = (p1 - p5) / p5; 
    ema50Slope = ema20Slope; 
  }

  let trendRegime: TrendRegime = 'SIDEWAYS_MARKET';
  const trendReasons: string[] = [];

  const isBull = price > sma200 && sma50 > sma200 && price > sma50;
  const isBear = price < sma200 && sma50 < sma200 && price < sma50;

  if (isBull) {
    trendRegime = 'BULL_MARKET';
    trendReasons.push('Close > SMA200');
    trendReasons.push('SMA50 > SMA200');
    trendReasons.push('Positive price trend');
  } else if (isBear) {
    trendRegime = 'BEAR_MARKET';
    trendReasons.push('Close < SMA200');
    trendReasons.push('SMA50 < SMA200');
    trendReasons.push('Negative price trend');
  } else {
    trendRegime = 'SIDEWAYS_MARKET';
    trendReasons.push('Price oscillating around moving averages');
  }

  // Volatility detection
  let volatilityRegime: VolatilityRegime = 'NORMAL_VOLATILITY';
  const atrRatio = atr14 / price;
  const volReasons: string[] = [];

  if (atrRatio > 0.035) { 
    volatilityRegime = 'HIGH_VOLATILITY';
    volReasons.push(`ATR ratio is high (${(atrRatio * 100).toFixed(2)}%)`);
  } else if (atrRatio < 0.012) {
    volatilityRegime = 'LOW_VOLATILITY';
    volReasons.push(`ATR ratio is low (${(atrRatio * 100).toFixed(2)}%)`);
  } else {
    volatilityRegime = 'NORMAL_VOLATILITY';
    volReasons.push(`ATR ratio is normal (${(atrRatio * 100).toFixed(2)}%)`);
  }

  // Confidence calculation
  let confidence = 0.5;
  if (trendRegime === 'BULL_MARKET' && price > sma20 && sma20 > sma50) {
    confidence += 0.25;
  } else if (trendRegime === 'BEAR_MARKET' && price < sma20 && sma20 < sma50) {
    confidence += 0.25;
  } else if (trendRegime === 'SIDEWAYS_MARKET' && Math.abs(price - sma200) / sma200 < 0.02) {
    confidence += 0.2;
  }

  if (volatilityRegime === 'HIGH_VOLATILITY' && atrRatio > 0.05) {
    confidence += 0.1;
  } else if (volatilityRegime === 'LOW_VOLATILITY' && atrRatio < 0.008) {
    confidence += 0.1;
  }

  const reasonText = [...trendReasons, ...volReasons].join(', ');

  return {
    trendRegime,
    volatilityRegime,
    regimeConfidence: Math.min(1, Math.max(0, confidence)),
    regimeReason: reasonText,
  };
}

import { HistoricalQuote } from '../types/stock';
import { EMA, RSI, MACD } from 'technicalindicators';

export type TrendDirection = 'BULLISH' | 'BEARISH' | 'NEUTRAL';

export interface TimeframeAnalysis {
  trendDirection: TrendDirection;
  trendStrength: number; // 0 to 1
  momentumState: TrendDirection;
}

export interface MultiTimeframeResult {
  alignmentScore: number; // 0 to 100
  alignmentDirection: TrendDirection;
  timeframeAgreementPercent: number; // 0 to 100
  alignmentConfidence: number; // 0 to 100
  timeframeConflict: boolean;
  conflictReason?: string;
  higherTimeframeTrend: TrendDirection;
  primaryTimeframeTrend: TrendDirection;
  lowerTimeframeMomentum: TrendDirection;
}

/**
 * Resamples daily bars into higher timeframe bars.
 */
export function resampleBars(bars: HistoricalQuote[], timeframe: 'W' | 'M'): HistoricalQuote[] {
  const resampled: HistoricalQuote[] = [];
  if (bars.length === 0) return resampled;

  let currentBar: Partial<HistoricalQuote> | null = null;
  let currentPeriodKey = '';

  for (const bar of bars) {
    const date = new Date(bar.date);
    let periodKey: string;

    if (timeframe === 'W') {
      // Get week number (rough approximation using UTC)
      const firstDayOfYear = new Date(Date.UTC(date.getUTCFullYear(), 0, 1));
      const pastDaysOfYear = (date.getTime() - firstDayOfYear.getTime()) / 86400000;
      const period = Math.ceil((pastDaysOfYear + firstDayOfYear.getUTCDay() + 1) / 7);
      periodKey = `${date.getUTCFullYear()}-W${period}`;
    } else {
      // Month
      periodKey = `${date.getUTCFullYear()}-M${date.getUTCMonth() + 1}`;
    }

    if (currentBar === null || currentPeriodKey !== periodKey) {
      if (currentBar) {
        resampled.push(currentBar as HistoricalQuote);
      }
      currentPeriodKey = periodKey;
      currentBar = {
        date: bar.date,
        open: bar.open,
        high: bar.high,
        low: bar.low,
        close: bar.close,
        volume: bar.volume,
      };
    } else {
      currentBar.high = Math.max(currentBar.high!, bar.high);
      currentBar.low = Math.min(currentBar.low!, bar.low);
      currentBar.close = bar.close;
      currentBar.volume! += bar.volume;
      currentBar.date = bar.date; // Use the end of the period date
    }
  }

  if (currentBar) {
    resampled.push(currentBar as HistoricalQuote);
  }

  return resampled;
}

/**
 * Analyzes a specific timeframe's bars to determine trend and momentum.
 */
export function analyzeTimeframe(bars: HistoricalQuote[], isLower: boolean = false): TimeframeAnalysis {
  if (bars.length < 50) {
    return { trendDirection: 'NEUTRAL', trendStrength: 0, momentumState: 'NEUTRAL' };
  }

  const closes = bars.map(b => b.close);
  const currentPrice = closes[closes.length - 1];

  // Moving Averages
  const ema20Arr = EMA.calculate({ values: closes, period: 20 });
  const ema50Arr = EMA.calculate({ values: closes, period: 50 });

  const ema20 = ema20Arr.length > 0 ? ema20Arr[ema20Arr.length - 1] : currentPrice;
  const ema50 = ema50Arr.length > 0 ? ema50Arr[ema50Arr.length - 1] : currentPrice;

  // RSI
  const rsiPeriod = isLower ? 5 : 14; // Use faster RSI for lower timeframe
  const rsiArr = RSI.calculate({ values: closes, period: rsiPeriod });
  const rsi = rsiArr.length > 0 ? rsiArr[rsiArr.length - 1] : 50;

  let trendDirection: TrendDirection = 'NEUTRAL';
  let trendStrength = 0;
  let momentumState: TrendDirection = 'NEUTRAL';

  // Determine Trend
  if (ema20 > ema50 && currentPrice > ema20) {
    trendDirection = 'BULLISH';
    trendStrength = Math.min(1, (currentPrice - ema50) / ema50 * 10);
  } else if (ema20 < ema50 && currentPrice < ema20) {
    trendDirection = 'BEARISH';
    trendStrength = Math.min(1, (ema50 - currentPrice) / ema50 * 10);
  }

  // Determine Momentum
  if (rsi > 60) momentumState = 'BULLISH';
  else if (rsi < 40) momentumState = 'BEARISH';

  return { trendDirection, trendStrength, momentumState };
}

/**
 * Calculates alignment across Higher, Primary, and Lower timeframes.
 */
export function calculateAlignment(
  higher: TimeframeAnalysis,
  primary: TimeframeAnalysis,
  lower: TimeframeAnalysis
): MultiTimeframeResult {
  let score = 50;
  let agreementCount = 0;
  let conflict = false;
  let conflictReason = '';

  const directions = [higher.trendDirection, primary.trendDirection, lower.momentumState];
  const bulls = directions.filter(d => d === 'BULLISH').length;
  const bears = directions.filter(d => d === 'BEARISH').length;

  let alignmentDirection: TrendDirection = 'NEUTRAL';

  if (bulls >= 2) alignmentDirection = 'BULLISH';
  if (bears >= 2) alignmentDirection = 'BEARISH';

  // Detect Conflicts
  if (higher.trendDirection === 'BULLISH' && primary.trendDirection === 'BEARISH') {
    conflict = true;
    conflictReason = 'Higher timeframe is Bullish, but Primary is Bearish.';
    score = 30;
  } else if (higher.trendDirection === 'BEARISH' && primary.trendDirection === 'BULLISH') {
    conflict = true;
    conflictReason = 'Higher timeframe is Bearish, but Primary is Bullish.';
    score = 30;
  } else if (primary.trendDirection === 'BULLISH' && lower.momentumState === 'BEARISH') {
    score = 60; // Minor conflict
  } else if (primary.trendDirection === 'BEARISH' && lower.momentumState === 'BULLISH') {
    score = 60; // Minor conflict
  } else if (higher.trendDirection === primary.trendDirection && primary.trendDirection !== 'NEUTRAL') {
    score = 80;
    agreementCount += 2;
    if (primary.trendDirection === lower.momentumState) {
      score = 95;
      agreementCount += 1;
    }
  }

  // Factor in trend strength
  if (score >= 80) {
    score += higher.trendStrength * 5;
    score = Math.min(100, score);
  }

  const timeframeAgreementPercent = Math.round((agreementCount / 3) * 100);

  return {
    alignmentScore: Math.round(score),
    alignmentDirection,
    timeframeAgreementPercent,
    alignmentConfidence: score, // Direct map for now
    timeframeConflict: conflict,
    conflictReason: conflictReason || undefined,
    higherTimeframeTrend: higher.trendDirection,
    primaryTimeframeTrend: primary.trendDirection,
    lowerTimeframeMomentum: lower.momentumState,
  };
}

